protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Preserve the EF Core 8 discriminator property name ("Discriminator" instead of the new "$type" default)
    // so existing documents and raw SQL queries like WHERE c.Discriminator = 'Blog' keep working.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Preserve the EF Core 8 id format ("Blog|1" instead of just "1")
    // so existing documents remain addressable.
    modelBuilder.Entity<Blog>().HasDiscriminatorInJsonId();

    // HasIndex() removed — Cosmos DB provider in EF Core 9 throws at runtime
    // because Cosmos does not support secondary indexes. The call was silently
    // ignored in EF Core 8 but is now a hard error.
}

